import { defineComponentSlotStyle } from "@yamada-ui/react"

export const indicatorStyle = defineComponentSlotStyle({
  base: {
    float: {
      zIndex: "yamcha",
    },
    label: {
      alignItems: "center",
      display: "inline-flex",
      rounded: "full",
      verticalAlign: "middle",
      whiteSpace: "nowrap",
      _numeric: {
        fontWeight: "medium",
      },
    },
    root: {
      position: "relative",
    },
  },

  props: {
    /**
     * If `true`, set the indicator as an inline element.
     *
     * @default false
     * */
    inline: {
      false: {
        root: {
          display: "block",
        },
      },
      true: {
        root: {
          display: "inline-block",
        },
      },
    },
    /**
     * If `true`, make an element scale and fade like a radar ping or ripple of water.
     *
     * @default false
     */
    ping: {
      true: {
        label: {
          _before: {
            animationDuration: "{duration, 1.4s}",
            animationFillMode: "forwards",
            animationIterationCount: "{iteration-count, infinite}",
            animationName: "ping",
            animationTimingFunction:
              "{timing-function, cubic-bezier(0, 0, 0.2, 1)}",
            bg: "{ping-color}",
            boxSize: "100%",
            inset: "0",
            opacity: 0.7,
            position: "absolute",
            rounded: "full",
            zIndex: -1,
          },
        },
        root: {
          "--animation-scale": "1.8",
        },
      },
    },
    /**
     * If `true`, display the border of the indicator.
     *
     * @default false
     */
    withBorder: {
      true: {
        label: {
          borderColor: ["white", "black"],
          borderWidth: "0.2em",
        },
      },
    },
  },

  variants: {
    solid: {
      label: {
        layerStyle: "solid",
        "--ping-color": "colorScheme.outline",
      },
    },
    subtle: {
      label: {
        layerStyle: "subtle",
        "--ping-color": "colorScheme.outline",
      },
    },
    surface: {
      label: {
        layerStyle: "surface",
        "--ping-color": "colorScheme.outline",
      },
    },
  },

  sizes: {
    sm: {
      label: {
        fontSize: "xs",
        minBoxSize: "3",
        _notEmpty: { px: "1.5" },
      },
    },
    md: {
      label: {
        fontSize: "sm",
        minBoxSize: "4",
        _notEmpty: { px: "2" },
      },
    },
    lg: {
      label: {
        fontSize: "md",
        minBoxSize: "5",
        _notEmpty: { px: "2.5" },
      },
    },
  },

  defaultProps: {
    size: "sm",
    variant: "solid",
    ping: false,
  },
})

export type IndicatorStyle = typeof indicatorStyle

import { a11y, page, render } from "#test/browser"
import { Indicator } from "."

describe("<Indicator />", () => {
  test("renders component correctly", async () => {
    await a11y(
      <Indicator label="New">
        <div />
      </Indicator>,
    )
  })

  test("sets `displayName`", () => {
    expect(Indicator.displayName).toBe("IndicatorRoot")
  })

  test("sets `className` correctly", async () => {
    await render(
      <Indicator data-testid="indicator" label="New">
        <div />
      </Indicator>,
    )
    const el = page.getByText("New").element()
    expect(el).toHaveClass("ui-indicator__label")
    expect(el.parentElement).toHaveClass("ui-indicator__float")
    expect(el.parentElement?.parentElement).toHaveClass("ui-indicator__root")
  })

  test("should render", async () => {
    await render(
      <Indicator label="New">
        <div />
      </Indicator>,
    )
    await expect.element(page.getByText("New")).toBeInTheDocument()
  })

  test("should render (with overflowCount)", async () => {
    await render(
      <Indicator
        label={100}
        overflowCount={99}
        labelProps={{ "data-testid": "indicator" }}
      >
        <div />
      </Indicator>,
    )
    await expect.element(page.getByTestId("indicator")).toHaveTextContent("+")
  })

  test("should not render zero when showZero is false", async () => {
    const { container } = await render(
      <Indicator
        label={0}
        showZero={false}
        labelProps={{ "data-testid": "indicator" }}
      >
        <div />
      </Indicator>,
    )
    expect(container.querySelector('[data-testid="indicator"]')).toBeNull()
  })

  test("should not render", async () => {
    const { container } = await render(
      <Indicator
        disabled
        label="New"
        labelProps={{ "data-testid": "indicator" }}
      >
        <div />
      </Indicator>,
    )
    expect(container.querySelector('[data-testid="indicator"]')).toBeNull()
  })

  test("should render zero when showZero is true", async () => {
    await render(
      <Indicator label={0} showZero labelProps={{ "data-testid": "indicator" }}>
        <div />
      </Indicator>,
    )
    await expect.element(page.getByTestId("indicator")).toHaveTextContent("0")
  })

  test("should render numeric label without overflow", async () => {
    const { container } = await render(
      <Indicator
        label={50}
        overflowCount={99}
        labelProps={{ "data-testid": "indicator" }}
      >
        <div />
      </Indicator>,
    )
    await expect.element(page.getByTestId("indicator")).toHaveTextContent("50")
    expect(container.textContent).not.toContain("+")
  })

  test("should set data-numeric attribute for numeric labels", async () => {
    await render(
      <Indicator label={10} labelProps={{ "data-testid": "indicator" }}>
        <div />
      </Indicator>,
    )
    await expect
      .element(page.getByTestId("indicator"))
      .toHaveAttribute("data-numeric")
  })

  test("should not set data-numeric attribute for non-numeric labels", async () => {
    await render(
      <Indicator label="New" labelProps={{ "data-testid": "indicator" }}>
        <div />
      </Indicator>,
    )
    await expect
      .element(page.getByTestId("indicator"))
      .not.toHaveAttribute("data-numeric")
  })

  test("should apply ping prop with boolean value", async () => {
    await render(
      <Indicator
        data-testid="indicator-root"
        label="New"
        ping
        labelProps={{ "data-testid": "indicator" }}
      >
        <div />
      </Indicator>,
    )
    const label = page.getByTestId("indicator").element()

    expect(label).toBeInTheDocument()
    // Verify the label element exists (ping affects pseudo-element styling)
    expect(label.parentElement).toHaveClass("ui-indicator__float")
  })

  test("should apply ping prop with object configuration", async () => {
    await render(
      <Indicator
        data-testid="indicator-root"
        label="New"
        ping={{
          color: "red.500",
          duration: "slower",
          iterationCount: "infinite",
          scale: "1.5",
          timingFunction: "ease-in-out",
        }}
        labelProps={{ "data-testid": "indicator" }}
      >
        <div />
      </Indicator>,
    )
    const root = page.getByTestId("indicator-root").element()
    const styles = getComputedStyle(root)

    expect(styles.getPropertyValue("--animation-scale")).toBe("1.5")
    expect(styles.getPropertyValue("--iteration-count")).toBe("infinite")
    expect(styles.getPropertyValue("--ping-color")).toBeTruthy()
    expect(styles.getPropertyValue("--duration")).toBeTruthy()
    expect(styles.getPropertyValue("--timing-function")).toBeTruthy()
  })

  test("should apply offset prop", async () => {
    await render(
      <Indicator
        label="New"
        offset={10}
        floatProps={{ "data-testid": "float-element" }}
        labelProps={{ "data-testid": "indicator" }}
      >
        <div />
      </Indicator>,
    )
    const floatElement = page.getByTestId("float-element").element()
    const styles = getComputedStyle(floatElement)

    expect(styles.getPropertyValue("--offset-block")).toBeTruthy()
    expect(styles.getPropertyValue("--offset-inline")).toBeTruthy()
  })

  test("should apply placement prop", async () => {
    await render(
      <Indicator
        label="New"
        placement="start-start"
        floatProps={{ "data-testid": "float-element" }}
        labelProps={{ "data-testid": "indicator" }}
      >
        <div />
      </Indicator>,
    )
    const floatElement = page.getByTestId("float-element").element()
    const label = page.getByTestId("indicator").element()

    // Verify Float element renders and contains the label
    expect(floatElement).toBeInTheDocument()
    expect(floatElement).toContainElement(label)
  })

  test("should apply floatProps", async () => {
    await render(
      <Indicator
        label="New"
        floatProps={{ "data-testid": "float-element" }}
        labelProps={{ "data-testid": "indicator" }}
      >
        <div />
      </Indicator>,
    )
    await expect.element(page.getByTestId("float-element")).toBeInTheDocument()
  })

  test("should apply custom className to labelProps", async () => {
    await render(
      <Indicator
        label="New"
        labelProps={{ className: "custom-label", "data-testid": "indicator" }}
      >
        <div />
      </Indicator>,
    )
    const label = page.getByTestId("indicator").element()
    expect(label).toHaveClass("custom-label")
  })
})

"use client"

import type { ReactNode } from "react"
import type { CSSProps, HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { FloatProps } from "../float"
import type { IndicatorStyle } from "./indicator.style"
import { useMemo } from "react"
import { createSlotComponent, styled, varAttr, dataAttr, isNumber, isObject } from "@yamada-ui/react"
import { Float } from "../float"
import { indicatorStyle } from "./indicator.style"

interface PingOptions {
  /**
   * It is used for the color of the ping animation.
   */
  color?: CSSProps["backgroundColor"]
  /**
   * It is used for the duration of the ping animation.
   */
  duration?: CSSProps["animationDuration"]
  /**
   * It is used for the count of the ping animation.
   */
  iterationCount?: CSSProps["animationIterationCount"]
  /**
   * It is used for the scale of the ping animation.
   */
  scale?: CSSProps["scale"]
  /**
   * It is used for the timing function of the ping animation.
   */
  timingFunction?: CSSProps["animationTimingFunction"]
}

export interface IndicatorProps
  extends
    Omit<HTMLStyledProps, "offset">,
    Omit<ThemeProps<IndicatorStyle>, "ping">,
    Pick<FloatProps, "offset" | "placement"> {
  /**
   * If `true`, the indicator will be disabled.
   *
   * @default false
   */
  disabled?: boolean
  /**
   * The indicator label to use.
   */
  label?: ReactNode
  /**
   * If `label` is of type number, the maximum number displayed.
   *
   * @default 99
   */
  overflowCount?: number
  /**
   * If `true`, make an element scale and fade like a radar ping or ripple of water.
   *
   * @default false
   */
  ping?: boolean | PingOptions
  /**
   * If `true`, display 0.
   *
   * @default true
   */
  showZero?: boolean
  /**
   * Props for the float element.
   */
  floatProps?: IndicatorFloatProps
  /**
   * Props for the label element.
   */
  labelProps?: IndicatorLabelProps
}

const {
  PropsContext: IndicatorPropsContext,
  usePropsContext: useIndicatorPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<IndicatorProps, IndicatorStyle>(
  "indicator",
  indicatorStyle,
)

export { IndicatorPropsContext, useIndicatorPropsContext }

/**
 * `Indicator` is a component that displays at the corner of elements such as avatars.
 *
 * @see https://yamada-ui.com/docs/components/indicator
 */
export const Indicator = withProvider(
  ({
    children,
    disabled,
    label,
    offset,
    overflowCount = 99,
    placement,
    showZero = true,
    floatProps,
    labelProps,
    ...rest
  }) => {
    const numeric = isNumber(label)

    disabled ??= numeric && !showZero && label <= 0

    const computedLabel = useMemo(() => {
      if (numeric && label > overflowCount) {
        return (
          <>
            {overflowCount}
            <styled.span>+</styled.span>
          </>
        )
      } else {
        return label
      }
    }, [numeric, label, overflowCount])

    return (
      <styled.div {...rest}>
        {children}

        {!disabled ? (
          <IndicatorFloat offset={offset} placement={placement} {...floatProps}>
            <IndicatorLabel data-numeric={dataAttr(numeric)} {...labelProps}>
              {computedLabel}
            </IndicatorLabel>
          </IndicatorFloat>
        ) : null}
      </styled.div>
    )
  },
  "root",
)(({ ping, ...rest }) => {
  if (isObject(ping)) {
    const { color, duration, iterationCount, scale, timingFunction } = ping

    return {
      ...rest,
      "--animation-scale": scale,
      "--duration": varAttr(duration, "durations"),
      "--iteration-count": iterationCount,
      "--ping-color": varAttr(color, "colors"),
      "--timing-function": varAttr(timingFunction, "easings"),
      ping: true,
    }
  } else {
    return { ...rest, ping }
  }
})

interface IndicatorFloatProps extends FloatProps {}

const IndicatorFloat = withContext<"div", IndicatorFloatProps>(Float, "float")()

interface IndicatorLabelProps extends HTMLStyledProps<"span"> {}

const IndicatorLabel = withContext<"span", IndicatorLabelProps>(
  "span",
  "label",
)()
